};

scwin.pwdNewYn_OnKillFocus = function() {
    if (pwdNewYn.getValue() == "1") {
        pwd.setMandatory(false);
        pwd.setDisabled(true);
    } else {
        pwd.setMandatory(true);
        pwd.setDisabled(false);
        pwd.focus();
    }
};

scwin.NewAmt = function() {
    if (GROUP1_mnrcvDstic1.getValue() == "91" || GROUP1_mnrcvDstic2.getValue() == "91" || GROUP1_mnrcvDstic3.getValue() == "91") {
        GROUP1_newamt.setDisabled(false);
    } else {
        GROUP1_newamt.setDisabled(true);
    }
};


scwin.GROUP1_mnrcvDstic1_OnItemChanged = function(e) {
    scwin.NewAmt();
    if (GROUP1_mnrcvDstic1.getSelectedIndex() == GROUP1_mnrcvDstic2.getSelectedIndex() ||
        GROUP1_mnrcvDstic1.getSelectedIndex() == GROUP1_mnrcvDstic3.getSelectedIndex()) {
