        GROUP1_mnrcvDstic1.clear();
        GROUP1_mnrcvDstic1.focus();
        return false;
    }
    if (GROUP1_mnrcvDstic1.getSelectedIndex() != "") {
        GROUP1_mrvamt1.setDisabled(false);
    } else {
        GROUP1_mrvamt1.setDisabled(true);
    }
};

