scwin.NewAmtACC = function() {
    var amt1 = 0;
    var amt2 = 0;
    var amt3 = 0;
    var AccNewAmt = 0;
    if (GROUP1_mrvamt1.getValue() == "") {
        amt1 = 0;
    } else {
        amt1 = parseFloat(GROUP1_mrvamt1.getValue());
    }
    if (GROUP1_mrvamt2.getValue() == "") {
        amt2 = 0;
    } else {
        amt2 = parseFloat(GROUP1_mrvamt2.getValue());
    }
    if (GROUP1_mrvamt3.getValue() == "") {
        amt3 = 0;
    } else {
        amt3 = parseFloat(GROUP1_mrvamt3.getValue());
    }
    if (rtchkAmy.getValue() == "") {
        ramt = 0;
    } else {
        ramt = parseFloat(rtchkAmy.getValue());
    }
    AccNewAmt = amt1 + amt2 + amt3;
    GROUP1_newamt.setValue(AccNewAmt);
};

scwin.GROUP1_mrvamt1_OnKillFocus = function() {
    scwin.NewAmtACC();
};

scwin.GROUP1_mrvamt2_OnKillFocus = function() {
    scwin.NewAmtACC();
};

scwin.GROUP1_mrvamt3_OnKillFocus = function() {
    scwin.NewAmtACC();
};


