scwin.GROUP6_idtrek_OnKillFocus = function() {
    if (parseFloat(GROUP6_idtrek.getValue()) > scwin.getDate()) {
        $c.iz.data.message("기산일은 현재날짜보다 클수 없습니다.");
        GROUP6_idtrek.setValue(scwin.getDate());
        GROUP6_idtrek.focus();
    }
};

//현재날짜(YYYYMMDD)
scwin.getDate = function() {
    var date = new Date();
    var strYmd = "";
    var strDate = "";
    var strMonth = "";
    strYmd += date.getFullYear().toString();
    strMonth = (date.getMonth() + 1).toString();
    if (strMonth < 10) strYmd += "0" + strMonth;

    else strYmd += strMonth;
    strDate = date.getDate();
    if (strDate < 10) strYmd += "0" + strDate;

    else strYmd += strDate;
    return strYmd;
};

scwin.GROUP6_salryTrsaccDte_OnKillFocus = function() {
    if (parseFloat(GROUP6_salryTrsaccDte.getValue()) < 1 || parseFloat(GROUP6_salryTrsaccDte.getValue()) > 31) {
        $c.iz.data.message("급여이체일의 입력 범위는 1~31 까지 입니다.");
        GROUP6_salryTrsaccDte.setValue();
        GROUP6_salryTrsaccDte.focus();
    }
};

scwin.OnSendKey = function() {
    //	SetTranID("KHC00110HC0000");
    //	Tran.ASend();
    if (prdctTmpltCd.getValue() == "") {
        $c.iz.data.alert("상품종류는 필수항목 입니다.", "필수항목 오류");
