        return;
    }
    //	if (GROUP3_lvtpSavnClam.Data == "" && GroupBox7.Visible == true)
    //	{
    //		Alert("생계형저축한도금액은 필수항목 입니다.","필수항목 오류");
    //		return;
    //	}
    if (GROUP2_solicEmpid.getValue() == "") {
        $c.iz.data.alert("권유직원번호는 필수항목 입니다.", "필수항목 오류");
        return;
    }
    if (GROUP2_solicBrncd.getValue() == "") {
        $c.iz.data.alert("권유점번호는 필수항목 입니다.", "필수항목 오류");
        return;
    }
    $c.iz.data.messageSlide("요구불신규:신규거래 신청서를 인자하세요");
    if (dpclssuncYn.getValue() == "1") {
        $c.iz.data.alert("요구불신규가 정상적으로 처리 되었습니다.\n\n직불카드 발급화면으로 이동합니다.", "정상처리");
        Link.acno = "00153700000123";
        $c.iz.screen.screenOpen("KJE00101000", "DATALINK");
    } else {
        $c.iz.data.alert("요구불신규가 정상적으로 처리 되었습니다.", "정상처리");
