scwin.prdctTmpltCd_OnItemChanged = function(e) {
    prdctTmpltNm.setValue(prdctTmpltCd.GetComboValue);
    scwin.goodsSelect();
    prdctSerno.clear();
    prdctnm.setValue();
    if (prdctTmpltCd.getValue() == "") {
        prdctTmpltNm.setValue();
    }
};

scwin.prdctSerno_OnItemChanged = function(e) {
    prdctnm.setValue(prdctSerno.GetComboValue);
    scwin.goodsSelect();
    if (prdctSerno.getValue() == "") {
        prdctTmpltCd.clear();
        prdctTmpltNm.setValue();
        prdctnm.setValue();
    }
};

scwin.goodsSelect = function() {
    //	세금우대 상품인 경우만 세금우대관련정보 그룹이 화면에 나타나고 그외는 안보이게 한다(세금우대정보 필드가 "Y"인 경우 DISPLAY)
    //	상품종류 : 002 세부상품종류 : 00001 인 경우 DISPLAY
    if (prdctTmpltCd.getValue() == "002" && prdctSerno.getValue() == "00001") {
        GroupBox7.show('');
        GroupBox8.hide();
        prdctnm.setValue("저축예금");
    } else if (prdctTmpltCd.getValue() == "003" && prdctSerno.getValue() == "00007") {
        GroupBox7.hide();
        GroupBox8.show('');
        prdctnm.setValue("KB우대기업자유");
        Edit40.setValue(5.00);
    } else {
        GroupBox7.hide();
        GroupBox8.hide();
    }
};

scwin.btnCusnmSch_OnClick = function(e) {
    if (inhabBzno.getValue() == "8801011234567") {
        Link.serchNo = inhabBzno.getValue();
        $c.iz.screen.popup("KAA04900000", "DATALINK");
        custnm.setValue(Link.custnm);
    } else {
        $c.iz.screen.popup("KAA00010000", "DATALINK");
    }
};


scwin.btnprdct_OnClick = function(e) {
    Link.prdctHanglName = prdctnm.getValue();
    Link.prdctLagClsfiCd = "01";
    Link.prdctMedmClsfiCd = "01";
    $c.iz.screen.popup("PDM04001000", "DATALINK");
    prdctnm.setValue(Link.prdctHanglName);
    prdctTmpltCd.setValue(Link.prdctTmpltCd);
    prdctSerno.setValue(Link.prdctNo);
    inhabBzno.focus();
};

