scwin.GROUP1_newamt_OnKillFocus = function() {
    if (GROUP1_newamt.getValue() != "") {
        var amt1 = 0;
        var amt2 = 0;
        var amt3 = 0;
        var ramt = 0;
        var AccNewAmt = 0;
        if (GROUP1_mrvamt1.getValue() == "") {
            amt1 = 0;
        } else {
            amt1 = parseFloat(GROUP1_mrvamt1.getValue());
        }
        if (GROUP1_mrvamt2.getValue() == "") {
