        }
        if (GROUP1_newamt.getValue() == "") {
            AccNewAmt = 0;
        } else {
            AccNewAmt = parseFloat(GROUP1_newamt.getValue());
        }

        //		if (rtchkAmy.Data == "")
        //		{
        //			ramt = 0;
        //		}
        //		else
        //		{
        //			ramt = parseFloat(rtchkAmy.Data);
        //		}
        ramt = amt1 + amt2 + amt3 - AccNewAmt;
        rtchkAmy.setValue(ramt);
    }
};
